import { Action } from 'redux';

import createReducer from '../store/createReducer';

export interface AdditionalCardRequestNameResponse {
  code: number;
  message: string;
  data: {
    nameIsValid: boolean;
    message?: string;
  };
}

export interface AdditionalCardRequestResponse {
  Cartao: string;
  Conta: string;
  pantoken?: string;
}

export type AdditionalCardCallback = (value: boolean) => void;

export enum AdditionalCardTypes {
  REQUEST_NAME = '@additionalCard/request_name',
  SUCCESS_NAME = '@additionalCard/success_name',
  FAILED_NAME = '@additionalCard/failed_name',
  SUCCESS_BIRTH_DATE = '@additionalCard/success_birth_date',
  SUCCESS_LIMIT = '@additionalCard/success_limit',
  REQUEST_ADDITIONAL_CARD = '@additionalCard/request',
  SUCCESS_ADDITIONAL_CARD = '@additionalCard/success',
  FAILED_ADDITIONAL_CARD = '@additionalCard/failed',
  CLEAR_ADDITIONAL_CARD = '@additionalCard/clear',
}

export interface AdditionalCardReducerProps {
  name: string;
  isLoadingName: boolean;
  isErrorName: boolean;
  errorNameMessage: string;
  birthDate: string;
  limit: string;
  isLoading: boolean;
  isError: boolean;
  errorMessage: string;
}

const initialState: AdditionalCardReducerProps = {
  name: '',
  isLoadingName: false,
  isErrorName: false,
  errorNameMessage: '',
  birthDate: '',
  limit: '',
  isLoading: false,
  isError: false,
  errorMessage: '',
};

const additionalCardReducer = createReducer(initialState, {
  [AdditionalCardTypes.REQUEST_NAME](
    state: AdditionalCardReducerProps,
    { name }: { name: string },
  ): AdditionalCardReducerProps {
    return {
      ...state,
      isLoadingName: true,
      isErrorName: false,
      name,
    };
  },
  [AdditionalCardTypes.SUCCESS_NAME](
    state: AdditionalCardReducerProps,
    { name }: { name: string },
  ): AdditionalCardReducerProps {
    return {
      ...state,
      isLoadingName: false,
      isErrorName: false,
      name,
    };
  },
  [AdditionalCardTypes.FAILED_NAME](
    state: AdditionalCardReducerProps,
    { errorNameMessage }: { errorNameMessage: string },
  ): AdditionalCardReducerProps {
    return {
      ...state,
      isLoadingName: false,
      isErrorName: true,
      errorNameMessage,
    };
  },
  [AdditionalCardTypes.SUCCESS_BIRTH_DATE](
    state: AdditionalCardReducerProps,
    { birthDate }: { birthDate: string },
  ): AdditionalCardReducerProps {
    return {
      ...state,
      birthDate,
    };
  },
  [AdditionalCardTypes.SUCCESS_LIMIT](
    state: AdditionalCardReducerProps,
    { limit }: { limit: string },
  ): AdditionalCardReducerProps {
    return {
      ...state,
      limit,
    };
  },
  [AdditionalCardTypes.REQUEST_ADDITIONAL_CARD](
    state: AdditionalCardReducerProps,
  ): AdditionalCardReducerProps {
    return {
      ...state,
      isLoading: true,
    };
  },
  [AdditionalCardTypes.SUCCESS_ADDITIONAL_CARD](
    state: AdditionalCardReducerProps,
  ): AdditionalCardReducerProps {
    return {
      ...state,
      isLoading: false,
    };
  },
  [AdditionalCardTypes.FAILED_ADDITIONAL_CARD](
    state: AdditionalCardReducerProps,
    { errorMessage }: { errorMessage: string },
  ): AdditionalCardReducerProps {
    return {
      ...state,
      isLoading: false,
      isError: true,
      errorMessage,
    };
  },
  [AdditionalCardTypes.CLEAR_ADDITIONAL_CARD](): AdditionalCardReducerProps {
    return initialState;
  },
});

type AdditionalCardActionsType = {
  requestName: (name: string, callback?: AdditionalCardCallback) => Action;
  successName: (name: string) => Action;
  failedName: (errorNameMessage?: string) => Action;
  successBirthDate: (birthDate: string) => Action;
  successLimit: (limit: string) => Action;
  requestAdditionalCard: (callback: AdditionalCardCallback) => Action;
  successAdditionalCard: () => Action;
  failedAdditionalCard: (errorMessage: string) => Action;
  clearAdditionalCard: () => Action;
};

export const additionalCardActions: AdditionalCardActionsType = {
  requestName: (name: string, callback?: AdditionalCardCallback) => ({
    type: AdditionalCardTypes.REQUEST_NAME,
    name,
    callback,
  }),
  successName: (name: string) => ({
    type: AdditionalCardTypes.SUCCESS_NAME,
    name,
  }),
  failedName: (errorNameMessage?: string) => ({
    type: AdditionalCardTypes.FAILED_NAME,
    errorNameMessage,
  }),
  successBirthDate: (birthDate: string) => ({
    type: AdditionalCardTypes.SUCCESS_BIRTH_DATE,
    birthDate,
  }),
  successLimit: (limit: string) => ({
    type: AdditionalCardTypes.SUCCESS_LIMIT,
    limit,
  }),
  requestAdditionalCard: (callback: AdditionalCardCallback) => ({
    type: AdditionalCardTypes.REQUEST_ADDITIONAL_CARD,
    callback,
  }),
  successAdditionalCard: () => ({
    type: AdditionalCardTypes.SUCCESS_ADDITIONAL_CARD,
  }),
  failedAdditionalCard: (errorMessage: string) => ({
    type: AdditionalCardTypes.FAILED_ADDITIONAL_CARD,
    errorMessage,
  }),
  clearAdditionalCard: () => ({
    type: AdditionalCardTypes.CLEAR_ADDITIONAL_CARD,
  }),
};

export default additionalCardReducer;

