import { Action } from 'redux';
import createReducer from '~/redux/store/createReducer';

export enum BlockCardTypes {
  REQUEST = '@blockCard/BLOCK_CARD_REQUEST',
  SUCCESS = '@blockCard/BLOCK_CARD_SUCCESS',
  FAILED = '@blockCard/BLOCK_CARD_FAILED',
  CLEAR = '@blockCard/BLOCK_CARD_CLEAR',
}

export interface BlockCardResponse {
  code: number;
  message: string;
  data: object;
}

export interface BlockCardReducerProps {
  isTemporary?: boolean;
  isLoading: boolean;
  isError: boolean;
  data: BlockCardResponse | undefined;
}

type State = BlockCardReducerProps;

const initialState: BlockCardReducerProps = {
  isTemporary: undefined,
  isLoading: false,
  isError: false,
  data: undefined,
};

export type BlockCardCallback = (data: {
  statusCode: number | undefined;
}) => void;

const blockCardReducer = createReducer(initialState, {
  [BlockCardTypes.REQUEST](
    state: State,
    {
      isTemporary,
    }: {
      isTemporary: boolean | undefined;
    },
  ) {
    return {
      ...state,
      isLoading: true,
      isTemporary,
    };
  },
  [BlockCardTypes.SUCCESS](
    state: State,
    {
      data,
    }: {
      data: BlockCardResponse;
    },
  ) {
    return {
      ...state,
      data,
      isLoading: false,
      isError: false,
    };
  },
  [BlockCardTypes.FAILED](
    state: State,
    {
      data,
    }: {
      data: BlockCardResponse;
    },
  ) {
    return {
      ...state,
      data,
      isLoading: false,
      isError: true,
    };
  },
  [BlockCardTypes.CLEAR](): State {
    return initialState;
  },
});

type BlockCardActions = {
  blockCardRequest: (
    isTemporary: boolean,
    lastFourNumbers: string,
    blockCode: string,
    callBack?: BlockCardCallback,
  ) => Action;
  blockCardSuccess: (data: { data: BlockCardResponse }) => Action;
  blockCardFailed: (data: { data: BlockCardResponse }) => Action;
  blockCardClear: () => Action;
};

export const blockCardActions: BlockCardActions = {
  blockCardRequest: (
    isTemporary: boolean,
    lastFourNumbers: string,
    blockCode: string,
    callBack?: BlockCardCallback,
  ) => ({
    type: BlockCardTypes.REQUEST,
    isTemporary,
    lastFourNumbers,
    blockCode,
    callBack,
  }),
  blockCardSuccess: (data: { data: BlockCardResponse }) => ({
    type: BlockCardTypes.SUCCESS,
    data,
  }),
  blockCardFailed: (data: { data: BlockCardResponse }) => ({
    type: BlockCardTypes.FAILED,
    data,
  }),
  blockCardClear: () => ({
    type: BlockCardTypes.CLEAR,
  }),
};

export default blockCardReducer;

